  ('generalpolice-8b7f1efc-moex-00236', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '內政部移民署許可港澳居民在臺定居之申請，為下列何種行政處分？', '["確認處分", "下命處分", "形成處分", "羈束處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00237', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '甲依法規申請補助，主管機關在法定處理期間經過後才作出申請否准之處分，甲接獲處分後未於 不變期間內提起訴願，上級機關得否依職權撤銷該處分之理由為何？', '["基於依法行政，處分不得違反包括處理期間在內所有上位階法規，上級機關應依職權撤銷", "因甲未進行救濟，該處分既已確定，上級機關不得依職權撤銷", "法定處理期間並非行政處分之合法要件，上級機關不得以逾越該期間為理由撤銷該處分", "不論其信賴是否值得保護，上級機關皆得依職權撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
